arguments.new_str:
using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelService
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly MLContext _mlContext;

    public TrainingMetrics? LastTrainingMetrics { get; private set; }

    public TicketModelService(string dataPath, string modelPath)
    {
        _mlContext = new MLContext(seed: 42);
        _dataPath = dataPath;
        _modelPath = modelPath;
    }

    public void TrainAndSave()
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeatures", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate(
                "Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        LastTrainingMetrics = new TrainingMetrics
        {
            MicroAccuracy = (float)metrics.MicroAccuracy,
            MacroAccuracy = (float)metrics.MacroAccuracy,
            LogLoss = (float)metrics.LogLoss,
            LogLossReduction = (float)metrics.LogLossReduction
        };

        Console.WriteLine($"Model metrics — MicroAccuracy: {metrics.MicroAccuracy:F4}, " +
                          $"MacroAccuracy: {metrics.MacroAccuracy:F4}, LogLoss: {metrics.LogLoss:F4}");

        _mlContext.Model.Save(model, data.Schema, _modelPath);
    }

    public string GetModelPath() => _modelPath;
}

